"use strict";

import React from 'react';
import PropTypes from 'prop-types';
import createReactClass from 'create-react-class';
import update from 'immutability-helper';
import suggestionProcessLabels from '@openagenda/labels/agenda-locations/suggestionProcess';
import get from '@openagenda/utils/get';
import post from '@openagenda/utils/post';
import makeLabelGetter from '@openagenda/labels';
import Spinner from '@openagenda/react-form-components/build/Spinner';
import LocationForm from './LocationForm';
import helpers from './suggestions.helpers.js';

var getLabel = makeLabelGetter( suggestionProcessLabels ),

validates = {
  email: require( '@openagenda/validators/email' )(),
  phone: require( '@openagenda/validators/phone' )(),
  text: require( '@openagenda/validators/text' )()
};

const stakeholderFields = {
  main : 'contactName',
  secondary: [ 'contactPosition', 'organization', 'contactNumber', 'contactEmail' ]
}

module.exports = createReactClass( {

  displayName: 'SuggestionProcessForm',

  propTypes: {

    lang: PropTypes.string.isRequired,

    location: PropTypes.object,

    res: PropTypes.shape( {

      getStakeholder: PropTypes.string,
      set: PropTypes.string,
      geocode: PropTypes.string,
      image: PropTypes.object

    } ).isRequired,

    // general admin actions ( see actions.js )
    actions: PropTypes.object,

    detailedInfo: PropTypes.bool

  },

  getInitialState() {

    return {
      isLoading: true,
      loadError: false,
      stakeholder: false,
      suggestionIndex: 0,
      location: this.props.actions.getState().form.location
    }

  },

  getDefaultProps() {

    return {
      suggestionIndex: 0,
      detailedInfo: false,
      settings: {}
    }

  },

  getSetRes() {

    return this.props.res.set + '?clearSuggestion=' + this.state.suggestionIndex;

  },

  componentWillMount() {

    this.loadSuggestion( this.state.suggestionIndex );

  },

  /**
   * get stakeholder for current suggestion
   */
  loadSuggestion( suggestionIndex = 0, force ) {

    if ( this.state.loading && !force ) return;

    let formState = this.props.actions.getState().form,

    stakeholderId = formState.location.suggestions[ this.state.suggestionIndex ].stakeholderId,

    res = this.props.res.getStakeholder
          .replace( ':stakeholderId', stakeholderId );

    this.setState( { loading: true } );

    get( res, ( err, stakeholder ) => {

      let updatedState = { loading: false };

      if ( err ) {

        updatedState.loadError = true;

      } else {

        updatedState.stakeholder = stakeholder;

        updatedState.suggestionIndex = suggestionIndex;

      }

      this.setState( updatedState );

    } );

  },

  discardSuggestion( e ) {

    e.preventDefault();

    let stakeholderId = this.props.actions.getState().form.location.suggestions[ this.state.suggestionIndex ].stakeholderId,

    locationUid = this.props.actions.getState().form.location.uid;

    if ( !stakeholderId ) {

      log( 'error', 'discard suggestion: stakholder id was not correctly specified' );

      return;

    }

    this.setState( { loading: true } );

    post( this.props.res.removeSuggestion.replace( ':locationUid', locationUid ), { stakeholderId: stakeholderId }, ( err, result ) => {

      if ( err ) {

        log( 'error', JSON.stringify( result ) );

        return this.setState( { loading: false } );

      }


      if ( this.state.location.suggestions.length > 1 ) {

        this.props.actions.removeSuggestion( this.state.suggestionIndex );

        let newIndex = this.state.location.suggestions.length - 1 <= this.state.suggestionIndex ? this.state.suggestionIndex - 1 : this.state.suggestionIndex;

        // annoying little hack to sync component location suggestion with general state..
        this.setState( {
          location: this.props.actions.getState().form.location
        } );

        this.loadSuggestion( newIndex, true );

      } else {

        this.props.actions.closeForm( update( this.state.location, { suggestions: { $set: [] } } ) );

      }

    } );

  },

  renderStakeholderInfo( info, i ) {

    let flattened = typeof info === 'string' ? info : info.label,

    matchingTypes = Object.keys( validates ).filter( f => {

      try {

        validates[ f ]( flattened );

      } catch( e ) {

        return false;

      }

      return true;

    } );

    if ( !matchingTypes.length ) return null;

    switch ( matchingTypes[ 0 ] ) {

      case 'phone': return <li key={i}><a href="tel:{info}">{flattened}</a></li>;

      case 'email': return <li key={i}><a href="mailto:{info}">{flattened}</a></li>;

      case 'text': return <li key={i}><span>{flattened}</span></li>;

    }

    return null;

  },

  navigateStakeholder( next ) {

    if ( next && this.state.suggestionIndex >= this.state.location.suggestions.length - 1 ) {

      return;

    }

    if ( !next && this.state.suggestionIndex === 0 ) {

      return;

    }

    this.loadSuggestion( this.state.suggestionIndex + ( next ? +1 : -1 ) );

  },

  onSuccess( location ) {

    if ( !location.suggestions.length ) {

      this.props.actions.updateEditedLocation( location, true );

      return;
      
    }

    this.setState( {
      location: location
    } );

    this.loadSuggestion();

  },

  renderSuggestionPager() {

    return this.state.location.suggestions.length > 1 ?
      <div className="text-center suggestion-nav">
        <a className={ this.state.suggestionIndex === 0 ? 'disabled' : '' } onClick={this.navigateStakeholder.bind( null, false )}>
          <i className="fa fa-arrow-left"></i>
        </a>
        <a href="#">{ this.state.suggestionIndex + 1 }/{ this.state.location.suggestions.length }</a>
        <a href="#" className={ this.state.suggestionIndex === this.state.location.suggestions.length - 1 ? 'disabled' : '' } onClick={this.navigateStakeholder.bind( null, true )}>
          <i className="fa fa-arrow-right"></i>
        </a>
      </div> : null;

  },

  renderHeader() {

    let stakeholderName = null,

      stakeholderInfo = null;

    if ( this.state.stakeholder ) {

      stakeholderName = this.state.stakeholder[ stakeholderFields.main ],

      stakeholderInfo = stakeholderFields.secondary
                        .filter( f => this.state.stakeholder[ f ] )
                        .map( f => this.state.stakeholder[ f ] );

    }

    return <div className="form-head">
      
      <a onClick={ this.props.actions.closeForm }>{ getLabel( 'back', this.props.lang ) }</a>
      
      <h2>{ getLabel( 'title', this.props.lang ) }</h2>
      <span className="info">{ getLabel( 'info', this.props.lang ) }</span>

      <div className="stakeholder">
        { this.renderSuggestionPager() }
        { stakeholderName ? <label>{ getLabel( 'suggestionFrom', { stakeholder: stakeholderName }, this.props.lang ) }</label>
        : <label>{ getLabel( 'suggestionUnknownFrom', this.props.lang ) }</label> }
        { stakeholderInfo ? <ul>{stakeholderInfo.map( this.renderStakeholderInfo ) }</ul> : <ul></ul> }
      </div>
      
    </div>

  },

  render() {

    if ( this.state.loading ) {

      return <Spinner/>

    }

    log( 'displaying suggestion process form' );

    let alt = helpers.prepareAlternatives( this.state.location, this.props, suggestionProcessLabels, this.state.suggestionIndex );

    // this.state.location has only the fields that have been suggested
    // for change that are set. This conflicts with data validation as
    // validation will attempt to clean all omitted data.

    console.log( alt.location );

    return <div>
      <LocationForm
        Header={ this.renderHeader() }
        labels={ suggestionProcessLabels }
        getSetRes={ this.getSetRes }
        location={ alt.location }
        alternatives={ alt.alternatives }
        lang={ this.props.lang }
        showToggler={ false }
        res={ this.props.res }
        cancel={ <a onClick={this.discardSuggestion} href="#" className="text-danger">{ getLabel( 'suggestionDiscard', this.props.lang ) }</a> }
        onSuccess={ this.onSuccess }
        settings={ this.props.settings }
        detailedInfo={ this.props.detailedInfo }
        disableNoAlternatives={ true }
        displayLanguageTabs={ false }
      />
    </div>

  }

} );

function log() {

  console.log.apply( console, arguments );

}